   213|function buildDashboardUrls(suffix: string): string[] {
   214|  const audit = getIVXOwnerAIConfigAudit();
   215|  const urls: string[] = [];
   216|  const push = (raw: string | null | undefined) => {
   217|    const trimmed = raw?.trim();
   218|    if (!trimmed || urls.includes(trimmed)) return;
   219|    urls.push(trimmed);
   220|  };
   221|  if (audit.activeBaseUrl) {
   222|    push(`${audit.activeBaseUrl.replace(/\/+$/, '')}${suffix}`);
   223|  }
   224|  for (const endpoint of audit.candidateEndpoints) {
   225|    const normalized = endpoint.replace(/\/+$/, '');
   226|    if (normalized.endsWith('/api/ivx/owner-ai')) {
   227|      push(`${normalized.slice(0, -'/api/ivx/owner-ai'.length)}${suffix}`);
   228|    } else if (normalized.endsWith('/ivx/owner-ai')) {
   229|      push(`${normalized.slice(0, -'/ivx/owner-ai'.length)}${suffix}`);
   230|    }
   231|  }
   232|  return urls;
