   235|async function ownerFetch<T>(suffix: string, init: RequestInit = {}): Promise<T> {
   236|  const accessToken = await getIVXAccessToken();
   237|  const tokenPresent = !!accessToken;
   238|  console.log('[IVXCTODashboardService] Owner token check', { tokenPresent });
   239|  if (!accessToken) {
   240|    throw new Error('Owner session token is not connected.');
   241|  }
   242|  const urls = buildDashboardUrls(suffix);
   243|  if (urls.length === 0) {
   244|    throw new Error('Owner AI backend URL is not configured.');
   245|  }
   246|  let lastError: Error | null = null;
   247|  for (const url of urls) {
   248|    try {
   249|      console.log('[IVXCTODashboardService] Sending request', { bearerHeaderPresent: true, url: suffix });
   250|      const response = await fetch(url, {
   251|        ...init,
   252|        headers: {
   253|          Accept: 'application/json',
   254|          'Content-Type': 'application/json',
   255|          Authorization: `Bearer ${accessToken}`,
   256|          ...(init.headers ?? {}),
   257|        },
   258|      });
   259|      const text = await response.text();
   260|      let payload: unknown = null;
   261|      try { payload = text ? JSON.parse(text) as unknown : null; } catch { payload = { error: text.slice(0, 240) }; }
   262|      if (!response.ok) {
   263|        const msg = isRecord(payload) ? (typeof payload.error === 'string' ? payload.error : '') : '';
   264|        throw new Error(msg || `CTO dashboard request failed (${response.status}).`);
   265|      }
   266|      return payload as T;
   267|    } catch (error) {
   268|      lastError = error instanceof Error ? error : new Error(String(error));
   269|      console.log('[IVXCTODashboardService] endpoint failed', { url, message: lastError.message });
   270|    }
   271|  }
   272|  throw lastError ?? new Error('CTO dashboard is not reachable.');
   273|}
