   413|// ---------- Routing ----------
   414|
   415|export function routeTaskToAgent(goal: string): AgentId {
   416|  const lower = goal.toLowerCase();
   417|  let bestAgent: AgentId = 'operations';
   418|  let bestScore = 0;
   419|  for (const id of ALL_AGENT_IDS) {
   420|    if (id === 'cto_orchestrator') continue;
   421|    const def = AGENTS[id];
   422|    let score = 0;
   423|    for (const kw of def.routingKeywords) {
   424|      if (lower.includes(kw)) score += 1;
   425|    }
   426|    if (score > bestScore) {
   427|      bestScore = score;
   428|      bestAgent = id;
   429|    }
   430|  }
   431|  return bestAgent;
   432|}
