   456|  }
   457|  recordAudit(fromAgent, 'handoff.send', `to=${toAgent} reason=${reason}`, taskId);
   458|  recordAudit(toAgent, 'handoff.receive', `from=${fromAgent}`, taskId);
   459|  return handoff;
   460|}
