   679|
   680|export function runFrameworkValidation(): { ok: boolean; checks: ValidationCheck[]; marker: string } {
   681|  const checks: ValidationCheck[] = [];
   682|
   683|  // 1. Routing
   684|  const backendRoute = routeTaskToAgent('Patch the Hono backend api endpoint for owner-ai');
   685|  checks.push({
   686|    name: 'routing.backend',
   687|    ok: backendRoute === 'backend_developer',
   688|    detail: `routed=${backendRoute}`,
   689|  });
   690|  const supabaseRoute = routeTaskToAgent('Add pgvector index to supabase schema migration');
   691|  checks.push({
   692|    name: 'routing.supabase',
   693|    ok: supabaseRoute === 'supabase_database',
   694|    detail: `routed=${supabaseRoute}`,
   695|  });
   696|  const sreRoute = routeTaskToAgent('Investigate render deploy failure and rollback');
   697|  checks.push({
   698|    name: 'routing.sre',
   699|    ok: sreRoute === 'infrastructure_sre',
   700|    detail: `routed=${sreRoute}`,
   701|  });
   702|  const investorRoute = routeTaskToAgent('Draft investor monthly report');
   703|  checks.push({
   704|    name: 'routing.investor',
   705|    ok: investorRoute === 'investor_relations',
   706|    detail: `routed=${investorRoute}`,
   707|  });
   708|
   709|  // 2. Handoff
   710|  const dispatched = dispatchTask({ goal: 'analyze frontend expo screen render performance' });
   711|  const hasInitialHandoff = dispatched.task.handoffs.length === 1
   712|    && dispatched.task.handoffs[0]?.fromAgent === 'cto_orchestrator';
   713|  checks.push({
   714|    name: 'handoff.initial',
   715|    ok: hasInitialHandoff,
   716|    detail: `handoffs=${dispatched.task.handoffs.length}`,
   717|  });
   718|  const secondary = recordHandoff(dispatched.task.assignedAgent, 'analytics', dispatched.task.id, 'need metrics');
   719|  checks.push({
   720|    name: 'handoff.secondary',
   721|    ok: secondary.toAgent === 'analytics' && getTask(dispatched.task.id)?.assignedAgent === 'analytics',
   722|    detail: `current=${getTask(dispatched.task.id)?.assignedAgent}`,
   723|  });
   724|
   725|  // 3. Memory namespacing
   726|  writeAgentMemory('backend_developer', 'last_patch', 'fixed owner-ai stream lock');
   727|  writeAgentMemory('frontend_developer', 'last_patch', 'updated chat screen scroll');
   728|  const backendMem = readAgentMemory('backend_developer', 'last_patch');
   729|  const frontendMem = readAgentMemory('frontend_developer', 'last_patch');
   730|  checks.push({
   731|    name: 'memory.namespaced',
   732|    ok: backendMem.length === 1 && frontendMem.length === 1
   733|      && backendMem[0]?.namespace !== frontendMem[0]?.namespace,
   734|    detail: `backendNs=${backendMem[0]?.namespace} frontendNs=${frontendMem[0]?.namespace}`,
   735|  });
   736|
   737|  // 4. Risk gating: high-risk task must be blocked without approver
   738|  const blocked = dispatchTask({ goal: 'DROP supabase production table and migrate schema' });
   739|  checks.push({
