   130|    regex = new RegExp(query, 'i');
   131|  } catch {
   132|    const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
   133|    regex = new RegExp(escaped, 'i');
   134|  }
   135|  const roots = pathPrefix ? [pathPrefix] : SCAN_INCLUDE_DIRS;
   136|  for (const root of roots) {
   137|    for await (const rel of walkFiles(root)) {
   138|      if (hits.length >= maxHits) return hits;
   139|      const full = safeResolve(rel);
   140|      if (!full) continue;
   141|      try {
   142|        const stat = await fs.stat(full);
   143|        if (stat.size > 256 * 1024) continue;
   144|        const text = await fs.readFile(full, 'utf8');
   145|        const lines = text.split('\n');
   146|        for (let i = 0; i < lines.length; i++) {
   147|          if (regex.test(lines[i] ?? '')) {
   148|            hits.push({ file: rel, line: i + 1, text: (lines[i] ?? '').slice(0, 240) });
   149|            if (hits.length >= maxHits) return hits;
   150|          }
   151|        }
   152|      } catch {
   153|        // ignore unreadable file
   154|      }
   155|    }
   156|  }
   157|  return hits;
   158|}
