   364|function runProcess(cmd: string, args: string[], timeoutMs: number): Promise<{ code: number | null; out: string; err: string; timedOut: boolean }> {
   365|  // Resolve an ABSOLUTE executable path so child_process never throws ENOENT
   366|  // when the bare command name (bun/bunx) is not on the spawned PATH.
   367|  const resolution = resolveRuntimeCommand(cmd as RuntimeName);
   368|  const resolvedCmd = resolution.resolvedPath ?? cmd;
   369|  return new Promise((resolve) => {
   370|    const child = spawn(resolvedCmd, args, { cwd: REPO_ROOT, env: process.env });
   371|    let out = '';
   372|    let err = '';
   373|    let timedOut = false;
   374|    const timer = setTimeout(() => {
   375|      timedOut = true;
   376|      try { child.kill('SIGTERM'); } catch { /* ignore */ }
   377|    }, timeoutMs);
   378|    child.stdout.on('data', (b: Buffer) => { out += b.toString('utf8'); if (out.length > 64 * 1024) out = out.slice(-64 * 1024); });
   379|    child.stderr.on('data', (b: Buffer) => { err += b.toString('utf8'); if (err.length > 64 * 1024) err = err.slice(-64 * 1024); });
   380|    child.on('close', (code) => { clearTimeout(timer); resolve({ code, out, err, timedOut }); });
   381|    child.on('error', (e) => { clearTimeout(timer); resolve({ code: null, out, err: err + '\n' + (e instanceof Error ? e.message : ''), timedOut }); });
   382|  });
   383|}
