   462|export async function toolTestRun(input: { suite?: string; incidentId?: string }) {
   463|  const suite = String(input.suite ?? 'typecheck');
   464|  if (suite === 'typecheck') {
   465|    // bun now ships in the production image (Gap #1), so the resolver finds it
   466|    // on PATH and we run a GENUINE native `bunx tsc --noEmit`. Only when bun is
   467|    // truly absent (e.g. a stripped runtime) do we degrade honestly to a real
   468|    // tsx import-smoke — never a fabricated pass.
   469|    const bunx = resolveRuntimeCommand('bunx');
   470|    if (!bunx.resolvedPath || bunx.usedFallback) {
   471|      return runImportSmokeValidation('typecheck');
   472|    }
   473|    const r = await runProcess('bunx', ['--bun', 'tsc', '-p', 'tsconfig.json', '--noEmit'], 120_000);
   474|    return { ok: r.code === 0 && !r.timedOut, suite, native: true as const, effectiveCheck: 'bunx-tsc' as const, exitCode: r.code, timedOut: r.timedOut, stdoutTail: r.out.slice(-4000), stderrTail: r.err.slice(-4000) };
   475|  }
   476|  if (suite === 'test') {
   477|    // Explicit native test execution (Gap #1).
   478|    const bun = resolveRuntimeCommand('bun');
   479|    if (!bun.resolvedPath || bun.usedFallback) {
   480|      return runImportSmokeValidation('test');
   481|    }
   482|    return runNativeBunTest('test');
   483|  }
   484|  if (suite === 'lint') {
   485|    const bun = resolveRuntimeCommand('bun');
   486|    if (!bun.resolvedPath || bun.usedFallback) {
   487|      return runImportSmokeValidation('lint');
   488|    }
   489|    // The expo eslint workspace is NOT shipped in the backend-only container, so
   490|    // the honest native check here is a real `bun test` execution of the shipped
   491|    // backend suites (Gap #1) rather than a degraded import-smoke. In a full
   492|    // checkout (local/sandbox) the expo lint script is present and runs natively.
   493|    if (await fileExists('expo/package.json')) {
   494|      const r = await runProcess('bun', ['run', '--cwd', 'expo', 'lint'], 120_000).catch(() => ({ code: null, out: '', err: 'lint script missing', timedOut: false }));
   495|      return { ok: r.code === 0, suite, native: true as const, effectiveCheck: 'bun-lint' as const, exitCode: r.code, timedOut: r.timedOut, stdoutTail: r.out.slice(-4000), stderrTail: r.err.slice(-4000) };
   496|    }
   497|    return runNativeBunTest('lint');
   498|  }
   499|  if (suite === 'smoke') {
   500|    const base = (process.env.PRODUCTION_BASE_URL || '').trim() || 'https://api.ivxholding.com';
   501|    try {
   502|      const res = await fetch(`${base.replace(/\/+$/, '')}/health`, { method: 'GET' });
   503|      const body = (await res.text()).slice(0, 2000);
   504|      return { ok: res.ok, suite, url: `${base}/health`, status: res.status, bodyPreview: body };
   505|    } catch (e) {
   506|      return { ok: false, suite, error: e instanceof Error ? e.message : 'smoke fetch failed' };
   507|    }
   508|  }
   509|  if (suite === 'replay') {
   510|    const id = typeof input.incidentId === 'string' ? input.incidentId.trim() : '';
   511|    if (!id) return { ok: false, error: 'incidentId is required for replay' };
   512|    const r = await replayIncidentAgainstStaging(id);
   513|    return { ok: r.ok, suite, result: r };
   514|  }
   515|  return { ok: false, error: `unknown suite '${suite}' (use typecheck|lint|smoke|replay)` };
   516|}
