export const IVX_AGENT_AUDIT_MARKER = 'ivx-agent-audit-2026-07-14';

// ── Types ────────────────────────────────────────────────────────────────────

export type CapabilityScore = 'PASS' | 'PARTIAL' | 'FAIL' | 'NOT_CONFIGURED';

